// prompt.js builds the [system,user] message pair exactly as
// internal/brain/prompt.go's BuildPrompt does for the integration-test path
// (Turn{Utterance} only): system = <preamble> + cards block; user =
// "User utterance:\n<text>". Each named export is one preamble variant so the
// promptfoo matrix can compare them in a single run. The cards block and the
// baseline preamble are generated byte-for-byte from Go (see braindump tool);
// candidate preambles live in variants/<name>.txt.
const fs = require('fs');
const path = require('path');

const CARDS = fs.readFileSync(path.join(__dirname, 'generated', 'cards_block.txt'), 'utf8');

// All preambles live in variants/ (baseline.txt is the frozen pre-iteration
// prompt; v5.txt is what ships today). generated/ holds only code-mirrored
// artifacts (cards block + schema + a preamble_shipped.txt reference snapshot).
function preamblePath(variant) {
  return path.join(__dirname, 'variants', variant + '.txt');
}

function make(variant) {
  let system; // lazily loaded so an absent variant file never breaks other prompts
  return async function ({ vars }) {
    if (!system) system = fs.readFileSync(preamblePath(variant), 'utf8') + CARDS;
    return JSON.stringify([
      { role: 'system', content: system },
      { role: 'user', content: 'User utterance:\n' + vars.utterance },
    ]);
  };
}

module.exports.baseline = make('baseline');
module.exports.v1 = make('v1');
module.exports.v2 = make('v2');
module.exports.v3 = make('v3');
module.exports.v4 = make('v4');
module.exports.v5 = make('v5');
module.exports.v6 = make('v6');
